// COMPLETE, COMPILABLE C code
#include <stdio.h>
#include <stdlib.h>
#define MAXN 10000
int parent[MAXN], rank[MAXN];
int find(int x) { return parent[x] == x ? x : (parent[x] = find(parent[x])); }
void unionSet(int x, int y) { int rootx = find(x), rooty = find(y);
if (rootx != rooty) { if (rank[rootx] > rank[rooty]) { parent[rooty] = rootx; }
else { parent[rootx] = rooty; if (rank[rootx] == rank[rooty]) rank[rooty]++; }}
}
int main() {
int T, M, ui, vi, i, j, k, count;
scanf("%d", &T);
while (T--) {
scanf("%d", &M);
for (i = 0; i < M; i++) {
scanf("%d %d", &ui, &vi);
// Initialize Union-Find for this edge
for (j = 0; j < MAXN; j++) { parent[j] = j; rank[j] = 0; }
// Check all intervals for this edge
count = 0;
for (j = 0; j <= i; j++) {
for (k = i; k < M; k++) {
// Add edges in the current interval to the Union-Find
if (j == 0 && k == i) {
if (find(ui - 1) != find(vi - 1)) unionSet(ui - 1, vi - 1);
else count++;
}
else {
scanf("%d %d", &ui, &vi);
if (find(ui - 1) != find(vi - 1)) unionSet(ui - 1, vi - 1);
}
}
}
printf("%d ", count);
}
printf("\n");
}
return 0;
}

